INSERT INTO plugin_cms_article ("category_id", "title", "subtitle", "slug", "summary", "cover", "author", "source", "content", "tags", "keywords", "description", "sort", "status", "is_top", "is_recommend", "views", "published_at", "created_at", "updated_at") VALUES
((SELECT "id" FROM plugin_cms_category WHERE "code"='1'), '研究院简介', '', 'cms-1', '启明先进材料产业研究院聚焦先进材料公共技术服务、成果转化和产业协同。', '', 'admin', '本站', '<p>启明先进材料产业研究院面向先进材料产业链提供技术研发、检测验证、人才培训和成果转化服务，建设开放共享的创新服务平台。</p>', '', '', '启明先进材料产业研究院聚焦先进材料公共技术服务、成果转化和产业协同。', 255, 1, 0, 0, 61, '2018-04-11 17:26:11', '2018-04-11 17:26:11', '2026-04-18 21:57:09'),
((SELECT "id" FROM plugin_cms_category WHERE "code"='4'), '产业智能化服务平台完成升级', '', 'cms-5', '研究院产业服务平台完成数据采集、项目协同和成果跟踪能力升级。', '', 'admin', '本站', '<p>研究院产业智能化服务平台完成升级，围绕项目申报、检测服务、成果转化和企业需求对接提供统一入口，提升服务响应效率。</p>', '', '', '研究院产业服务平台完成数据采集、项目协同和成果跟踪能力升级。', 255, 1, 0, 0, 4, '2018-04-12 09:52:36', '2018-04-12 10:06:15', '2018-04-13 09:36:44'),
((SELECT "id" FROM plugin_cms_category WHERE "code"='4'), '青年科研交流活动顺利开展', '', 'cms-6', '青年科研交流活动围绕先进材料应用场景和项目协作展开。', '', 'admin', '本站', '<p>青年科研交流活动顺利开展，参会团队围绕先进材料应用场景、实验平台共建和企业需求对接进行了专题交流。</p>', '', '', '青年科研交流活动围绕先进材料应用场景和项目协作展开。', 255, 1, 0, 0, 5, '2018-04-12 10:06:22', '2018-04-12 10:08:03', '2018-04-13 09:36:25'),
((SELECT "id" FROM plugin_cms_category WHERE "code"='4'), '“站得稳”才“靠得住”（思想纵横）', '', 'cms-7', '习近平总书记强调：“任何时候任何情况下，党的领导干部在政治上都要站得稳、靠得住”。“站得稳”和“靠得住”，是党员领导干部至关重要的能力素养。“站得稳”，才能在复杂环境中保持冷静、坚定立场，有效应对压力和挑战，蹄疾步稳、扎扎实实做好各项工作；“靠得住”，才能凝心聚力，赢得党和人民的信任，有效发挥“', '', 'admin', '本站', '&lt;p style=&quot;box-sizing: border-box; margin: 10px auto; padding: 0px; -webkit-tap-highlight-color: transparent; color: rgb(51, 51, 51); white-space: normal; outline: 0px; border: 0px; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; background-color: rgb(255, 255, 255);&quot;&gt;&lt;span style=&quot;box-sizing: border-box; font-size: 16px;&quot;&gt;&lt;span style=&quot;color: #333333; font-family: 微软雅黑; font-size: 16px; background-color: #FFFFFF;&quot;&gt;　　&lt;/span&gt;习近平总书记强调：“任何时候任何情况下，党的领导干部在政治上都要站得稳、靠得住”。“站得稳”和“靠得住”，是党员领导干部至关重要的能力素养。“站得稳”，才能在复杂环境中保持冷静、坚定立场，有效应对压力和挑战，蹄疾步稳、扎扎实实做好各项工作；“靠得住”，才能凝心聚力，赢得党和人民的信任，有效发挥“头雁效应”，团结带领大家同心同德干事业。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;box-sizing: border-box; margin: 10px auto; padding: 0px; -webkit-tap-highlight-color: transparent; color: rgb(51, 51, 51); white-space: normal; outline: 0px; border: 0px; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; background-color: rgb(255, 255, 255);&quot;&gt;&lt;span style=&quot;box-sizing: border-box; font-size: 16px;&quot;&gt;　　在工作中，“站得稳”具体表现为一种扎实稳当的工作作风。党员领导干部“站得稳”，才能做到每临大事有静气，时刻保持清醒头脑，有主见、有定力。“靠得住”，体现能力和品质。党员领导干部“靠得住”，才能在平淡无奇中不消沉，在狂风骤雨前不畏缩，在鲜花掌声中不迷失，始终保持昂扬向上干事创业的精气神。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;box-sizing: border-box; margin: 10px auto; padding: 0px; -webkit-tap-highlight-color: transparent; color: rgb(51, 51, 51); white-space: normal; outline: 0px; border: 0px; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; background-color: rgb(255, 255, 255);&quot;&gt;&lt;span style=&quot;box-sizing: border-box; font-size: 16px;&quot;&gt;　　“站得稳”与“靠得住”，二者相互依存、相互强化、辩证统一。“站得稳”为“靠得住”筑基固本，“靠得住”为“站得稳”保驾护航。“站得稳”，需要具备坚定理想信念、高尚思想境界、过硬工作能力、坚强党性原则和丰富经验积累。这样，才能在重大风险考验前面不改色，当泰山压顶时敢于担当，面对各种诱惑不为所动，在关键时刻让党信得过、让群众有主心骨。对于党员领导干部而言，“靠得住”是政治品格、政治品质的试金石。只有“靠得住”，才能担当起应该担当的责任，遇到急难险重任务不推诿、不逃避，面对群众急难愁盼，既以“等不起”的紧迫感用心用力把急事难事办妥，又以“放不下”的责任感把关系群众切身利益的事办实办好。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;box-sizing: border-box; margin: 10px auto; padding: 0px; -webkit-tap-highlight-color: transparent; color: rgb(51, 51, 51); white-space: normal; outline: 0px; border: 0px; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; background-color: rgb(255, 255, 255);&quot;&gt;&lt;span style=&quot;box-sizing: border-box; font-size: 16px;&quot;&gt;　　“站得稳”与“靠得住”，既是能力素养，更是党性修养。党性修养强，能力素养才过硬。如果遇事只计个人得失、只为自身打算，见到歪风邪气默不作声、遇到“矛盾窝子”绕而不钻、碰到“烫手山芋”推而不接；或者政治定力不强、党性修养不够，面对“乱花渐欲迷人眼”的各种诱惑乱了心、张了口、伸了手，这样的领导干部是靠不住的，也难以站得稳、立得住。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;box-sizing: border-box; margin: 10px auto; padding: 0px; -webkit-tap-highlight-color: transparent; color: rgb(51, 51, 51); white-space: normal; outline: 0px; border: 0px; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; background-color: rgb(255, 255, 255);&quot;&gt;&lt;span style=&quot;box-sizing: border-box; font-size: 16px;&quot;&gt;　　“花繁柳密处拨得开，才是手段；风狂雨急时立得定，方见脚根。”“站得稳”与“靠得住”并不是自然形成的，而是在实践中不断锻造出来的。党员领导干部只有筑牢信仰之基、补足精神之钙、把稳思想之舵，面对精心设计的“围猎”陷阱、拉拢腐蚀，确保政治上不生锈、不褪色、不变质、不变味；在时间紧、任务重、压力大时不逃避、不退缩，在摸爬滚打中提升能力本领；面对盘根错节、掰扯不清、争执不休的矛盾问题不推诿甩锅，在条分缕析中磨炼心性；在滴水穿石、愚公移山式的历史性工程中不骄不躁，一锤一锤钉钉子，一代一代接力干，才是真正“站得稳”“靠得住”。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;box-sizing: border-box; margin: 10px auto; padding: 0px; -webkit-tap-highlight-color: transparent; color: rgb(51, 51, 51); white-space: normal; outline: 0px; border: 0px; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-stretch: normal; font-size: 18px; line-height: 36px; font-family: 微软雅黑; background-color: rgb(255, 255, 255);&quot;&gt;&lt;span style=&quot;box-sizing: border-box; font-size: 16px;&quot;&gt;　　做到“站得稳”与“靠得住”，不在一时一事而在一生一世，需要坚持不懈、久久为功。习近平总书记指出：“干部的党性修养、道德水平，不会随着党龄工龄的增长而自然提高，也不会随着职务的升迁而自然提高，必须强化自我修炼、自我约束、自我改造。”现实中，有的年轻干部刚上任就落马，也有的领导干部刚退休就身陷囹圄，其中一个重要原因在于放松了思想改造，站偏了、靠歪了。只有不断进行自我检视、剖析、反思，不断去杂质、除病毒、防污染，才能真正立得正、站得稳、走得远、靠得住。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;', '', '', '习近平总书记强调：“任何时候任何情况下，党的领导干部在政治上都要站得稳、靠得住”。“站得稳”和“靠得住”，是党员领导干部至关重要的能力素养。“站得稳”，才能在复杂环境中保持冷静、坚定立场，有效应对压力和挑战，蹄疾步稳、扎扎实实做好各项工作；“靠得住”，才能凝心聚力，赢得党和人民的信任，有效发挥“', 255, 1, 0, 0, 40, '2018-04-12 10:08:50', '2018-04-12 10:09:37', '2026-04-18 21:58:25'),
